/**
 * Pi hook bridge — runs the repo's Claude-format shell hook scripts on Pi.
 *
 * Pi has no shell `hooks.json`; it exposes TS callbacks. This generic bridge maps
 * Pi's events onto the Claude hook protocol so the SAME shell scripts (the single
 * source of truth) run unchanged:
 *
 *   Pi `tool_call`          -> Claude PreToolUse      (can block: {block:true,reason})
 *   Pi `input`              -> Claude UserPromptSubmit (block via {action:"handled"})
 *
 * It reads `manifest.json` (a sibling file generated by bin/adapters/pi.sh listing
 * each pi-targeted plugin's hooks with ABSOLUTE script + pluginRoot paths), builds
 * a Claude-shaped payload, pipes it to the script on stdin with CLAUDE_PLUGIN_ROOT
 * set, and translates the script's decision back:
 *   - stdout `{"decision":"block","reason":...}` (exit 0)  -> block
 *   - exit code 2 (reason on stderr)                       -> block
 *   - anything else                                        -> allow (never break the agent)
 *
 * Installed by pi.sh as ~/.pi/agent/extensions/hook-bridge/ (auto-discovered).
 */
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { execFileSync } from "node:child_process";
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

type HookEntry = { event: string; matcher?: string | null; script: string; pluginRoot: string };

const here = dirname(fileURLToPath(import.meta.url));
let HOOKS: HookEntry[] = [];
try {
  HOOKS = JSON.parse(readFileSync(join(here, "manifest.json"), "utf8")).hooks ?? [];
} catch {
  // No manifest -> no hooks to bridge. Stay silent and inert.
}

// Pi built-in tool name -> Claude tool name (matchers are written in Claude terms).
const PI_TO_CLAUDE: Record<string, string> = { write: "Write", edit: "Edit" };

type Decision = { block: boolean; reason?: string };

function runScript(entry: HookEntry, payload: unknown, cwd?: string): Decision {
  try {
    const out = execFileSync("bash", [entry.script], {
      input: JSON.stringify(payload),
      encoding: "utf8",
      timeout: 10_000,
      cwd,
      env: { ...process.env, CLAUDE_PLUGIN_ROOT: entry.pluginRoot },
    });
    const text = (out || "").trim();
    if (text) {
      try {
        const d = JSON.parse(text);
        if (d && d.decision === "block") return { block: true, reason: d.reason };
      } catch {
        // non-JSON stdout on exit 0 -> treat as allow
      }
    }
    return { block: false };
  } catch (e: any) {
    if (e && e.status === 2) {
      const reason = (e.stderr ? String(e.stderr) : "").trim();
      return { block: true, reason: reason || "Blocked by hook" };
    }
    return { block: false }; // any other failure: allow, never break the agent
  }
}

export default function (pi: ExtensionAPI) {
  // PreToolUse: Pi edit/write -> Claude Edit/Write. write_file/replace etc. fall
  // through PI_TO_CLAUDE unmapped and are ignored.
  pi.on("tool_call", async (event: any, ctx: any) => {
    const claudeTool = PI_TO_CLAUDE[event.toolName];
    if (!claudeTool) return undefined;
    const input = event.input ?? {};
    // Normalize Pi's `path` into Claude's `file_path`; pass everything else through
    // so content/new_string-style fields reach the script when names line up.
    const tool_input = { ...input, file_path: input.path ?? input.file_path };
    for (const h of HOOKS) {
      if (h.event !== "PreToolUse") continue;
      if (h.matcher && !new RegExp(h.matcher).test(claudeTool)) continue;
      const d = runScript(
        h,
        { hook_event_name: "PreToolUse", tool_name: claudeTool, tool_input, cwd: ctx?.cwd },
        ctx?.cwd,
      );
      if (d.block) {
        if (ctx?.hasUI) ctx.ui.notify(d.reason ?? "Blocked by hook", "warning");
        return { block: true, reason: d.reason ?? "Blocked by hook" };
      }
    }
    return undefined;
  });

  // UserPromptSubmit: Pi `input` event. The scripts self-gate on their trigger
  // (e.g. the prompt mentioning deep-review), so this fires the script on every
  // prompt and blocks only when the script says so.
  pi.on("input", async (event: any, ctx: any) => {
    if (event.source === "extension") return { action: "continue" };
    for (const h of HOOKS) {
      if (h.event !== "UserPromptSubmit") continue;
      const d = runScript(h, { hook_event_name: "UserPromptSubmit", prompt: event.text }, ctx?.cwd);
      if (d.block) {
        if (ctx?.hasUI) ctx.ui.notify(d.reason ?? "Blocked by hook", "warning");
        return { action: "handled" };
      }
    }
    return { action: "continue" };
  });
}
